import{_ as s,c as e,o as a,a2 as i}from"./chunks/framework.CriqKoQt.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"docs/2026上/vue3-uniapp-sourcemap.md","filePath":"docs/2026上/vue3-uniapp-sourcemap.md","lastUpdated":1776394004000}'),o={name:"docs/2026上/vue3-uniapp-sourcemap.md"};function p(n,t,r,l,c,d){return a(),e("div",null,t[0]||(t[0]=[i('<h2 id="分析结论" tabindex="-1">分析结论 <a class="header-anchor" href="#分析结论" aria-label="Permalink to &quot;分析结论&quot;">​</a></h2><p>非 setup 的 <code>&lt;script lang=&quot;ts&quot;&gt;</code> 在 sourcemap 生成时会产生冲突。具体原因如下：</p><h3 id="根本原因" tabindex="-1">根本原因 <a class="header-anchor" href="#根本原因" aria-label="Permalink to &quot;根本原因&quot;">​</a></h3><p>当一个 <code>.vue</code> 文件使用 <code>&lt;script lang=&quot;ts&quot;&gt;</code>（非 setup）时，Vite 的处理链路是：</p><ol><li><strong><code>@vitejs/plugin-vue</code></strong> 先将 <code>.vue</code> 文件拆分为 template、script、style 三个虚拟模块</li><li><strong>template 部分</strong>编译后会生成 render 函数，其 sourcemap 指向原始 <code>.vue</code> 文件</li><li><strong>script 部分</strong>（<code>&lt;script lang=&quot;ts&quot;&gt;</code>）需要经过 <strong>TypeScript 编译</strong>，其 sourcemap 也指向原始 <code>.vue</code> 文件</li><li>最终 rollup 在 <code>traceMappings()</code> 中合并 sourcemap 时，发现<strong>同一个源文件（<code>index.vue</code>）对应了两份不同的 <code>sourcesContent</code></strong>——一份来自 template 的 transform，一份来自 script 的 TypeScript transform</li></ol><p>关键代码在 rollup 的 <code>traceMappings()</code> 中（第 20113-20114 行）：</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (content </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> null</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sourcesContent[sourceIndex] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!==</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> content) {</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> error</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">logConflictingSourcemapSources</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(filename));</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>当同一个 filename 被两个不同的 transform 链处理后，产生了不同的 <code>sourcesContent</code>，就会触发这个错误。</p><h3 id="为什么-script-setup-lang-ts-不会报错" tabindex="-1">为什么 <code>&lt;script setup lang=&quot;ts&quot;&gt;</code> 不会报错？ <a class="header-anchor" href="#为什么-script-setup-lang-ts-不会报错" aria-label="Permalink to &quot;为什么 `&lt;script setup lang=&quot;ts&quot;&gt;` 不会报错？&quot;">​</a></h3><p><code>&lt;script setup&gt;</code> 的编译方式不同——setup script 会被 <code>@vitejs/plugin-vue</code> 在 SFC 编译阶段<strong>一起处理</strong>（template 和 script 合并编译），生成的是一个统一的 sourcemap，不会出现同一个源文件有多份不同 content 的情况。</p><h3 id="为什么-pvp-next-不报错" tabindex="-1">为什么 pvp-next 不报错？ <a class="header-anchor" href="#为什么-pvp-next-不报错" aria-label="Permalink to &quot;为什么 pvp-next 不报错？&quot;">​</a></h3><p>pvp-next 的 vue 文件全部使用的是 <code>&lt;script&gt;</code>（纯 JS，不带 <code>lang=&quot;ts&quot;</code>），<strong>不需要经过 TypeScript 编译这一步</strong>，所以不会产生额外的 sourcemap transform 链，自然不会出现冲突。</p><h3 id="对比总结" tabindex="-1">对比总结 <a class="header-anchor" href="#对比总结" aria-label="Permalink to &quot;对比总结&quot;">​</a></h3><table tabindex="0"><thead><tr><th>对比项</th><th>val-match-next</th><th>pvp-next</th></tr></thead><tbody><tr><td>script 类型</td><td><code>&lt;script lang=&quot;ts&quot;&gt;</code> (15个) + <code>&lt;script setup lang=&quot;ts&quot;&gt;</code> (41个)</td><td><code>&lt;script&gt;</code> (纯 JS)</td></tr><tr><td>TS 编译</td><td>需要额外的 TS transform</td><td>不需要</td></tr><tr><td>sourcemap 冲突</td><td>✅ template + TS 两条链产生不同 content</td><td>❌ 只有一条链</td></tr></tbody></table><h3 id="解决方案" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案" aria-label="Permalink to &quot;解决方案&quot;">​</a></h3><p>有以下几种方式：</p><ol><li><p><strong>方案一（最简单）</strong>：在 <code>vite.config.ts</code> 中关闭 sourcemap</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">buildOptions</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sourcemap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div></li><li><p><strong>方案二（推荐，保留 sourcemap 功能）</strong>：将报错的 <code>&lt;script lang=&quot;ts&quot;&gt;</code> 改为 <code>&lt;script setup lang=&quot;ts&quot;&gt;</code>，这样 SFC 编译器会统一处理 template 和 script 的 sourcemap</p></li></ol>',17)]))}const g=s(o,[["render",p]]);export{u as __pageData,g as default};
